import './App.css';
import { BrowserRouter, Routes, Route, Link, NavLink, Navigate, useLocation } from 'react-router-dom';
import { useEffect, useState } from 'react';
import axios from 'axios';
import Getproducts from './components/Home';
import Signup from './components/Signup';
import Signin from './components/Signin';
import Notfound from './components/Notfound';
import 'bootstrap/dist/css/bootstrap.min.css';
import Makepayment from './components/Makepayment';
import Rooms from './components/Rooms';
import RoomDetails from './components/RoomDetails';
import Dining from './components/Dining';
import Bookings from './components/Bookings';
import Contactus from './components/Contactus';
import EventInquiry from './components/EventInquiry';
import AdminPanel from './components/Admin';
import { clearStoredAuth, getStoredAuth, isAdminUser, setStoredAuth } from './utils/auth';
import { buildApiUrl } from './utils/api';

const AUTH_VALIDATE_URL = buildApiUrl('/auth/validate');

function AdminRoute() {
  const authState = getStoredAuth();
  const user = authState?.user;
  const token = authState?.token;
  const [isValidating, setIsValidating] = useState(Boolean(token));
  const [hasValidSession, setHasValidSession] = useState(Boolean(token && isAdminUser(user)));

  useEffect(() => {
    let isMounted = true;

    async function validateSession() {
      if (!token || !isAdminUser(user)) {
        if (isMounted) {
          setHasValidSession(false);
          setIsValidating(false);
        }
        return;
      }

      try {
        const response = await axios.get(AUTH_VALIDATE_URL, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        if (!isMounted) {
          return;
        }

        setStoredAuth({
          user: response.data.user,
          token,
          expiresInSeconds: response.data.expires_in,
        });
        setHasValidSession(isAdminUser(response.data.user));
      } catch (error) {
        if (!isMounted) {
          return;
        }

        clearStoredAuth();
        setHasValidSession(false);
      } finally {
        if (isMounted) {
          setIsValidating(false);
        }
      }
    }

    validateSession();

    return () => {
      isMounted = false;
    };
  }, [token, user]);

  if (isValidating) {
    return <main className="container py-5">Checking admin session...</main>;
  }

  if (!hasValidSession) {
    return <Navigate to="/signin" replace />;
  }

  return <AdminPanel />;
}

function AppLayout() {
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);
  const isHomePage = location.pathname === '/';

  useEffect(() => {
    setMenuOpen(false);
  }, [location.pathname, location.hash]);

  useEffect(() => {
    window.scrollTo({
      top: 0,
      left: 0,
      behavior: 'auto',
    });
  }, [location.key]);

  return (
    <div className="App">
      <header className={`site-header ${isHomePage ? 'site-header--home' : ''}`}>
        <div className="site-header__inner">
          <Link to="/" className="site-brand">
            <span className="site-brand__mark">EH</span>
            <span className="site-brand__text">
              <strong>ELITEHOTELS</strong>
              <small>Hotel & Restaurant</small>
            </span>
          </Link>

          <button
            type="button"
            className={`site-nav__toggle ${menuOpen ? 'is-open' : ''}`}
            onClick={() => setMenuOpen((open) => !open)}
            aria-label="Toggle navigation"
            aria-expanded={menuOpen}
          >
            <span></span>
            <span></span>
            <span></span>
          </button>

          <nav className={`site-nav ${menuOpen ? 'is-open' : ''}`}>
            <Link to="/rooms" className="site-nav__link">Rooms</Link>
            <Link to="/dining" className="site-nav__link">Dining</Link>
            <Link to="/bookings" className="site-nav__link">Bookings</Link>
            <Link to="/contactus" className="site-nav__link">Contact Us</Link>
            <NavLink to="/signin" className="site-nav__link">Sign In</NavLink>
            <NavLink to="/signup" className="site-nav__link">Sign Up</NavLink>
          </nav>
        </div>
      </header>

      <Routes>
        <Route path="/" element={<Getproducts />} />
        <Route path="/signup" element={<Signup />} />
        <Route path="/signin" element={<Signin />} />
        <Route path="/rooms" element={<Rooms />} />
        <Route path="/rooms/:roomSlug" element={<RoomDetails />} />
        <Route path="/dining" element={<Dining />} />
        <Route path="/bookings" element={<Bookings />} />
        <Route path="/contactus" element={<Contactus />} />
        <Route path="/events" element={<EventInquiry />} />
        <Route path="/makepayment" element={<Makepayment />} />
        <Route path="/admin" element={<AdminRoute />} />
        <Route path="*" element={<Notfound />} />
      </Routes>

      <footer className="site-footer">
        <div className="site-footer__inner">
          <div className="site-footer__brand">
            <Link to="/" className="site-brand site-footer__brand-link">
              <span className="site-brand__mark">EH</span>
              <span className="site-brand__text">
                <strong>ELITEHOTELS</strong>
                <small>Hotel & Restaurant</small>
              </span>
            </Link>
            <p>
              Elegant rooms, memorable dining, and warm hospitality designed to make every stay
              feel special.
            </p>
          </div>

